div.script:
(function () {
var dialSelect = document.getElementById('mc-dial-code');
var numberInput = document.getElementById('mc-mobile-number');
var hiddenInput = document.getElementById('mobile');

if (!dialSelect || !numberInput || !hiddenInput) return;

/* On error re-render: parse stored value back into dropdown + number */
var stored = (hiddenInput.value || '').trim();
if (stored) {
/* Find the longest matching dial code */
var opts = Array.from(dialSelect.options);
var matched = opts
.filter(function(o) { return stored.startsWith(o.value); })
.sort(function(a, b) { return b.value.length - a.value.length; })[0];
if (matched) {
dialSelect.value = matched.value;
numberInput.value = stored.slice(matched.value.length).replace(/^\s+/, '');
} else {
numberInput.value = stored;
}
}

/* Combine dial code + number into hidden field */
function sync() {
var code = dialSelect.value;
var number = numberInput.value.trim();
hiddenInput.value = number ? (code + ' ' + number) : '';
}

dialSelect.addEventListener('change', sync);
numberInput.addEventListener('input', sync);

/* Sync once on load in case values are already set */
sync();
})();
